  1→import React, { useState, useMemo, useCallback, useEffect, lazy, Suspense } from 'react';
  2→import { User, AnalysisResult, SMCContent, GeneratedSolution } from './types';
  3→import { analyzeUrl } from './services/analyzer';
  4→import { db } from './services/database';
  5→import Home from './pages/Home';
  6→import Login from './pages/Login';
  7→import Analyze from './pages/Analyze';
  8→
  9→// Lazy-loaded pages for bundle optimization
 10→const Dashboard = lazy(() => import('./pages/Dashboard'));
 11→const GenerativeTools = lazy(() => import('./pages/GenerativeTools'));
 12→const Results = lazy(() => import('./pages/Results').then(m => ({ default: m.Results })));
 13→const HistoryView = lazy(() => import('./pages/History'));
 14→const SMCStudio = lazy(() => import('./pages/SMCStudio'));
 15→const SourceOfTruth = lazy(() => import('./pages/SourceOfTruth'));
 16→const SchemaOrg = lazy(() => import('./pages/SchemaOrg'));
 17→const PublisherRequest = lazy(() => import('./pages/PublisherRequest'));
 18→const RobotsTxt = lazy(() => import('./pages/RobotsTxt'));
 19→const Directory = lazy(() => import('./pages/Directory'));
 20→const DirectoryEntity = lazy(() => import('./pages/DirectoryEntity'));
 21→const Recharge = lazy(() => import('./pages/Recharge'));
 22→const Projects = lazy(() => import('./pages/Projects'));
 23→const Account = lazy(() => import('./pages/Account'));
 24→const Clients = lazy(() => import('./pages/Clients'));
 25→const Affiliation = lazy(() => import('./pages/Affiliation'));
 26→const ContentWriter = lazy(() => import('./pages/ContentWriter'));
 27→const Reputation = lazy(() => import('./pages/Reputation'));
 28→const BotTracking = lazy(() => import('./pages/BotTracking'));
 29→const Messages = lazy(() => import('./pages/Messages'));
 30→const AlertsAEO = lazy(() => import('./pages/AlertsAEO'));
 31→const MissionOrders = lazy(() => import('./pages/MissionOrders'));
 32→import {
 33→  LogOut, Zap, Github, Twitter, Linkedin, Home as HomeIcon, LayoutDashboard,
 34→  Globe, ScanLine, Menu, CreditCard, FolderOpen, FileText, FileCode, History,
 35→  Fuel, User as UserIcon, PenTool, Code, ClipboardList, ChevronDown, ChevronRight,
 36→  Archive, CheckSquare, Sparkles, Users, MessageSquare, Bell, ShoppingBag,
 37→  Settings, Construction, BarChart3, Wrench, Share2, Feather, Shield, X
 38→} from 'lucide-react';
 39→import { I18nProvider, useTranslation, LanguageSelector } from './i18n';
 40→
 41→const PLAN_LIMITS = {
 42→  free: 1,
 43→  pro: 3,
 44→  enterprise: 1000 // Illimité en pratique
 45→};
 46→
 47→const App: React.FC = () => {
 48→  return (
 49→    <I18nProvider>
 50→      <AppContent />
 51→    </I18nProvider>
 52→  );
 53→};
 54→
 55→const AppContent: React.FC = () => {
 56→  const { t, tf, locale } = useTranslation();
 57→  const [currentView, setCurrentView] = useState<'home' | 'analyze' | 'results' | 'directory' | 'directory-entity' | 'login' | 'projects' | 'source-of-truth' | 'robots-txt' | 'history' | 'recharge' | 'account' | 'publisher-request' | 'schema-org' | 'smc-studio' | 'dashboard' | 'generative-tools' | 'clients' | 'affiliation' | 'messages' | 'alerts' | 'content-writer' | 'reputation' | 'bot-tracking' | 'mission-orders'>('home');
 58→  const [viewHistory, setViewHistory] = useState<string[]>([]);
 59→  const [refreshKey, setRefreshKey] = useState(0); // Used to force remount of components
 60→  
 61→  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
 62→  const [history, setHistory] = useState<AnalysisResult[]>([]);
 63→  
 64→  // Load history from DB on mount
 65→  useEffect(() => {
 66→    const loadedHistory = db.getAll();
 67→    setHistory(loadedHistory);
 68→  }, []);
 69→
 70→  // Bibliothèques de contenu généré
 71→  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]); 
 72→  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
 73→  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
 74→  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);
 75→
 76→  const [isAnalyzing, setIsAnalyzing] = useState(false);
 77→  const [resultsTab, setResultsTab] = useState<'overview' | 'details' | 'archives' | 'recommendations'>('overview');
 78→  const [publisherRequestData, setPublisherRequestData] = useState<{ topic: string, url: string, brief: string } | null>(null);
 79→  const [initialRechargePackId, setInitialRechargePackId] = useState<number | null>(null);
 80→  const [initialAccountTab, setInitialAccountTab] = useState<'profile' | 'subscription' | 'billing'>('profile');
 81→  
 82→  // État pour gérer l'ouverture des sections du menu (Accordion exclusif)
 83→  const [sectionsState, setSectionsState] = useState({
 84→    optimization: false,
 85→    tools: false
 86→  });
 87→  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
 88→
 89→  // Default user is NULL to allow testing the login flow
 90→  const [user, setUser] = useState<User | null>(null);
 91→
 92→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
 93→  const monthlyProjectCount = useMemo(() => {
 94→    if (history.length === 0) return 0;
 95→
 96→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
 97→    const now = new Date();
 98→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
 99→
100→    // 1. Identifier la date de création (première analyse) de chaque domaine
101→    const projectCreationDates = new Map<string, Date>();
102→    
103→    history.forEach(h => {
104→        let hostname;
105→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
106→        
107→        const analysisDate = new Date(h.timestamp);
108→        
109→        if (!projectCreationDates.has(hostname)) {
110→            projectCreationDates.set(hostname, analysisDate);
111→        } else {
112→            // On garde la date la plus ancienne trouvée pour ce domaine
113→            if (analysisDate < projectCreationDates.get(hostname)!) {
114→                projectCreationDates.set(hostname, analysisDate);
115→            }
116→        }
117→    });
118→
119→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
120→    let count = 0;
121→    projectCreationDates.forEach((creationDate) => {
122→        if (creationDate >= billingCycleStart) {
123→            count++;
124→        }
125→    });
126→    
127→    return count;
128→  }, [history]);
129→
130→  const navigateTo = (view: typeof currentView) => {
131→    setIsMobileMenuOpen(false);
132→    // Si on navigue vers autre chose que recharge, on reset l'ID du pack
133→    if (view !== 'recharge') {
134→        setInitialRechargePackId(null);
135→    }
136→    // Reset l'onglet du compte si on ne va pas vers le compte
137→    if (view !== 'account') {
138→        setInitialAccountTab('profile');
139→    }
140→    setViewHistory(prev => [...prev, currentView]);
141→    setCurrentView(view);
142→    setRefreshKey(prev => prev + 1); // Force remount to reset internal state of views
143→  };
144→
145→  const goBack = () => {
146→    setIsMobileMenuOpen(false);
147→    if (viewHistory.length > 0) {
148→      const newHistory = [...viewHistory];
149→      const prevView = newHistory.pop();
150→      setViewHistory(newHistory);
151→      if (prevView) {
152→        setCurrentView(prevView as any);
153→        setRefreshKey(prev => prev + 1);
154→      }
155→    } else {
156→      setCurrentView('home'); // Default fallback
157→      setRefreshKey(prev => prev + 1);
158→    }
159→  };
160→
161→  const toggleSection = (section: keyof typeof sectionsState) => {
162→    setSectionsState(prev => {
163→      const isAlreadyOpen = prev[section];
164→      return {
165→        optimization: false,
166→        tools: false,
167→        [section]: !isAlreadyOpen
168→      };
169→    });
170→  };
171→
172→  const handleHomeClick = () => {
173→    navigateTo('home');
174→    setSectionsState({
175→      optimization: false,
176→      tools: false
177→    });
178→  };
179→
180→  const handleDashboardClick = () => {
181→    navigateTo('dashboard');
182→    setSectionsState({
183→      optimization: false,
184→      tools: false
185→    });
186→  };
187→
188→  const handleRechargeClick = () => {
189→    navigateTo('recharge');
190→    setSectionsState({
191→      optimization: false,
192→      tools: false
193→    });
194→  };
195→
196→  const handleDirectRecharge = (packId: number) => {
197→    setInitialRechargePackId(packId);
198→    navigateTo('recharge');
199→  };
200→
201→  const handleAnalyze = async (url: string) => {
202→    // Vérification de la limite de projets (Quota mensuel)
203→    if (user) {
204→        const limit = PLAN_LIMITS[user.plan] || 1;
205→        let hostname = url;
206→        try { hostname = new URL(url).hostname; } catch(e) {}
207→
208→        // On vérifie si c'est un projet déjà existant dans l'historique global
209→        const isExistingProject = history.some(h => {
210→            try { return new URL(h.url).hostname === hostname; } 
211→            catch(e) { return false; }
212→        });
213→
214→        // Si c'est un tout nouveau projet et qu'on a atteint la limite MENSUELLE
215→        // Les anciens projets ne comptent pas dans cette limite
216→        if (!isExistingProject && monthlyProjectCount >= limit) {
217→            // Redirection vers l'onglet Abonnement
218→            alert(`Limite de nouveaux projets atteinte pour ce mois (${monthlyProjectCount}/${limit}). Passez au plan supérieur pour ajouter plus de projets.`);
219→            setInitialAccountTab('subscription');
220→            navigateTo('account');
221→            return;
222→        }
223→    }
224→
225→    setIsAnalyzing(true);
226→    try {
227→      const result = await analyzeUrl(url);
228→      setAnalysisData(result);
229→      
230→      // Update history via DB service
231→      const updatedHistory = db.add(result);
232→      setHistory(updatedHistory);
233→      
234→      // Redirection vers Monitoring AEO (Projects)
235→      navigateTo('projects');
236→      setSectionsState({
237→        optimization: false,
238→        tools: false
239→      });
240→    } catch (error) {
241→      console.error("Analysis failed", error);
242→      alert("Erreur lors de l'analyse. Veuillez réessayer.");
243→    } finally {
244→      setIsAnalyzing(false);
245→    }
246→  };
247→
248→  // Used for Admin/User private analysis view
249→  const handleViewAnalysis = (result: AnalysisResult, tab: any = 'overview') => {
250→    setAnalysisData(result);
251→    setResultsTab(tab);
252→    // Redirect to Projects (Monitoring AEO) instead of Results (Report)
253→    navigateTo('projects');
254→    setSectionsState({
255→        optimization: true,
256→        tools: false
257→    });
258→  };
259→
260→  // New handler for Public Directory View
261→  const handleViewDirectoryEntity = (result: AnalysisResult) => {
262→    setAnalysisData(result);
263→    navigateTo('directory-entity');
264→  };
265→
266→  const handleSubMenuNavigation = (tab: 'overview' | 'details' | 'archives') => {
267→    if (analysisData) {
268→      setResultsTab(tab);
269→      navigateTo('results');
270→    } else if (history.length > 0) {
271→      handleViewAnalysis(history[0], tab);
272→    } else {
273→      alert("Veuillez d'abord lancer une analyse pour accéder au plan d'actions.");
274→      navigateTo('analyze');
275→    }
276→  };
277→
278→  const handleUpdateAnalysis = (index: number, updatedData: Partial<AnalysisResult>) => {
279→    const updatedHistory = db.update(index, updatedData);
280→    setHistory(updatedHistory);
281→  };
282→
283→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
284→    const timestamp = new Date().toISOString();
285→    const solutionWithMeta = { ...solution, timestamp };
286→
287→    setAnalysisData(prev => {
288→        if (!prev || prev.timestamp !== analysisId) return prev;
289→        
290→        return {
291→            ...prev,
292→            generatedSolutions: {
293→                ...(prev.generatedSolutions || {}),
294→                [recommendationId]: solutionWithMeta
295→            }
296→        };
297→    });
298→
299→    // We need to find the index in the history to update the DB
300→    setHistory(prevHistory => {
301→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
302→        if (index !== -1) {
303→            const updatedItem = {
304→                ...prevHistory[index],
305→                generatedSolutions: {
306→                    ...(prevHistory[index].generatedSolutions || {}),
307→                    [recommendationId]: solutionWithMeta
308→                }
309→            };
310→            // Persist using db service
311→            const newHistory = [...prevHistory];
312→            newHistory[index] = updatedItem;
313→            // Note: calling db.update relies on index which matches prevHistory order if initialized from DB
314→            db.update(index, updatedItem);
315→            return newHistory;
316→        }
317→        return prevHistory;
318→    });
319→  }, []); 
320→
321→  // Helpers pour ajouter du contenu aux bibliothèques
322→  const handleAddToSmcLibrary = (item: SMCContent) => setSmcLibrary(prev => [item, ...prev]);
323→  const handleAddToTruthLibrary = (item: SMCContent) => setTruthLibrary(prev => [item, ...prev]);
324→  const handleAddToSchemaLibrary = (item: SMCContent) => setSchemaLibrary(prev => [item, ...prev]);
325→  const handleAddToRobotsLibrary = (item: SMCContent) => setRobotsLibrary(prev => [item, ...prev]);
326→
327→  const handleNavigateToPublisher = (data: { topic: string, url: string, brief: string }) => {
328→    setPublisherRequestData(data);
329→    navigateTo('publisher-request');
330→  };
331→
332→  const handleNavigateToDirectory = () => {
333→    navigateTo('directory');
334→  };
335→
336→  const handleDeductCredits = (amount: number): boolean => {
337→    if (!user) {
338→        if(confirm("Vous devez être connecté pour effectuer cette action. Se connecter maintenant ?")) {
339→            navigateTo('login');
340→        }
341→        return false;
342→    }
343→    
344→    if (user.credits < amount) {
345→        // Redirection explicite vers la section GTO Gas (Recharge)
346→        alert(`Solde GTO Gas insuffisant pour générer cette solution.\n\nIl vous manque ${amount - user.credits} crédits.\n\nRedirection vers la station de recharge...`);
347→        navigateTo('recharge');
348→        return false;
349→    }
350→    
351→    setUser(prev => prev ? { ...prev, credits: prev.credits - amount } : null);
352→    return true;
353→  };
354→
355→  const handleRecharge = (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => {
356→    if (!user) return;
357→    
358→    setUser({ 
359→        ...user, 
360→        credits: user.credits + amount,
361→        plan: planLevel 
362→    });
363→    
364→    // Si c'est une recharge depuis la page de recharge, on ne force pas le retour, l'UX est gérée dans Recharge.tsx
365→  };
366→
367→  const handleUpgradePlan = (newPlan: 'free' | 'pro' | 'enterprise') => {
368→    if (!user) return;
369→    setUser({ ...user, plan: newPlan });
370→  };
371→
372→  const handleLogin = (loggedInUser: User) => {
373→    setUser(loggedInUser);
374→    // On réinitialise l'historique pour éviter que le bouton retour ne renvoie au login
375→    // et on force la navigation vers le dashboard
376→    setViewHistory(['home']); 
377→    setCurrentView('analyze'); // Redirection vers Nouvel Audit
378→    setRefreshKey(prev => prev + 1);
379→  };
380→
381→  const handleLogout = () => {
382→    setIsMobileMenuOpen(false);
383→    setUser(null);
384→    setCurrentView('home');
385→    setViewHistory([]);
386→    setRefreshKey(prev => prev + 1);
387→  };
388→
389→  useEffect(() => {
390→    if (!user && isMobileMenuOpen) {
391→      setIsMobileMenuOpen(false);
392→    }
393→  }, [user, isMobileMenuOpen]);
394→
395→  useEffect(() => {
396→    if (!isMobileMenuOpen) return;
397→    const previousOverflow = document.body.style.overflow;
398→    document.body.style.overflow = 'hidden';
399→    return () => {
400→      document.body.style.overflow = previousOverflow;
401→    };
402→  }, [isMobileMenuOpen]);
403→
404→  const NavItem = ({ view, label, icon: Icon, onClick, active }: { view?: typeof currentView, label: string, icon: React.ElementType, onClick?: () => void, active?: boolean }) => {
405→    const handleClick = onClick ? onClick : () => view && navigateTo(view);
406→    const isActive = active !== undefined ? active : (view && currentView === view);
407→    
408→    return (
409→      <button
410→        onClick={handleClick}
411→        className={`w-full flex items-center gap-3 px-3.5 py-2.5 rounded-xl text-[14px] transition-all duration-200 group font-sans ${
412→          isActive
413→            ? 'bg-white/[0.08] text-white font-semibold'
414→            : 'text-gray-500 hover:text-white hover:bg-white/[0.04] font-medium'
415→        }`}
416→      >
417→        <Icon size={17} className={isActive ? "text-purple-400" : "text-gray-600 group-hover:text-gray-300"} />
418→        <span>{label}</span>
419→      </button>
420→    );
421→  };
422→
423→  const PlaceholderView = ({ title, icon: Icon }: { title: string, icon: React.ElementType }) => (
424→    <div className="flex flex-col items-center justify-center h-[80vh] text-center p-8 animate-in fade-in zoom-in duration-300">
425→      <div className="w-24 h-24 bg-white/5 rounded-full flex items-center justify-center mb-6 shadow-inner border border-white/10">
426→        <Icon size={48} className="text-gray-500 opacity-50" />
427→      </div>
428→      <h2 className="text-3xl font-serif font-bold text-white mb-4">{title}</h2>
429→      <p className="text-gray-400 max-w-md mb-8">
430→        {t.common.featureInDev}
431→      </p>
432→      <button
433→        onClick={() => navigateTo('dashboard')}
434→        className="px-6 py-3 bg-white/10 hover:bg-white/20 text-white rounded-xl transition-all flex items-center gap-2 font-medium"
435→      >
436→        <LayoutDashboard size={18} /> {t.common.returnToDashboard}
437→      </button>
438→    </div>
439→  );
440→
441→  return (
442→    <div className="min-h-screen flex flex-col font-sans text-gray-100 selection:bg-primary/30 bg-black">
443→      {/* NinjaPromo-style Floating Pill Navbar */}
444→      <nav className="sticky top-0 z-50 px-4 pt-3">
445→        <div className="max-w-7xl mx-auto bg-[#111111] rounded-full px-6 h-14 flex items-center justify-between border border-white/[0.06] shadow-lg shadow-black/30">
446→          <div className="flex items-center gap-2.5">
447→            {user && (
448→              <button
449→                type="button"
450→                onClick={() => setIsMobileMenuOpen(prev => !prev)}
451→                className="md:hidden w-9 h-9 rounded-full border border-white/[0.08] bg-white/[0.03] text-gray-300 hover:text-white hover:bg-white/[0.06] transition-colors flex items-center justify-center"
452→                aria-label={isMobileMenuOpen ? "Fermer le menu" : "Ouvrir le menu"}
453→                aria-expanded={isMobileMenuOpen}
454→                aria-controls="mobile-sidebar-menu"
455→              >
456→                {isMobileMenuOpen ? <X size={17} /> : <Menu size={17} />}
457→              </button>
458→            )}
459→            <div
460→              className="flex items-center gap-2.5 cursor-pointer"
461→              onClick={() => navigateTo('home')}
462→            >
463→            <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center text-white font-bold font-serif text-base">
464→              C
465→            </div>
466→            <span className="font-sans text-lg font-bold tracking-tight hidden sm:block text-white">CitedBy.ai</span>
467→            </div>
468→          </div>
469→
470→          <div className="flex items-center gap-5">
471→            {user ? (
472→              <div className="flex items-center gap-3">
473→                <LanguageSelector compact />
474→                <button
475→                  onClick={() => navigateTo('recharge')}
476→                  className="hidden md:flex items-center gap-1.5 px-3 py-1 rounded-full hover:bg-white/5 transition-colors group"
477→                  title="Recharger GTO Gas"
478→                >
479→                  <Fuel size={14} className="text-primary fill-primary group-hover:animate-pulse" />
480→                  <span className="text-sm font-bold text-white group-hover:text-primary">{user.credits}</span>
481→                </button>
482→                <div className="h-6 w-px bg-white/10 hidden md:block"></div>
483→                <div className="flex items-center gap-2.5">
484→                   <div
485→                     className="text-right hidden sm:block cursor-pointer"
486→                     onClick={() => navigateTo('account')}
487→                   >
488→                     <p className="text-sm font-medium text-white leading-none hover:text-primary transition-colors">{user.name}</p>
489→                     <p className="text-[10px] text-gray-500 uppercase tracking-wider mt-0.5">{user.plan.toUpperCase()}</p>
490→                   </div>
491→                   <button
492→                    title="Mon Compte"
493→                    onClick={() => navigateTo('account')}
494→                    className="w-8 h-8 rounded-full bg-white/5 border border-white/10 text-white text-sm font-bold flex items-center justify-center hover:border-primary/50 transition-colors"
495→                   >
496→                     {user.name.charAt(0).toUpperCase()}
497→                   </button>
498→                </div>
499→              </div>
500→            ) : (
501→              <div className="flex items-center gap-3">
502→                <LanguageSelector compact />
503→                <button
504→                  onClick={() => navigateTo('login')}
505→                  className="btn-gradient text-sm !py-2 !px-5"
506→                >
507→                  {t.nav.login}
508→                </button>
509→              </div>
510→            )}
511→          </div>
512→        </div>
513→      </nav>
514→
515→      {user && (
516→        <>
517→          <div
518→            className={`md:hidden fixed inset-0 z-40 bg-black/70 backdrop-blur-sm transition-opacity duration-300 ${
519→              isMobileMenuOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
520→            }`}
521→            onClick={() => setIsMobileMenuOpen(false)}
522→          />
523→          <aside
524→            id="mobile-sidebar-menu"
525→            className={`md:hidden fixed top-0 left-0 bottom-0 z-50 w-[84%] max-w-[320px] bg-[#111111] border-r border-white/[0.08] shadow-2xl shadow-black/50 transform transition-transform duration-300 ease-out ${
526→              isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'
527→            }`}
528→          >
529→            <div className="h-full flex flex-col pt-20 pb-6 px-4 overflow-y-auto">
530→              <div className="bg-black/40 border border-white/[0.06] rounded-2xl p-3 space-y-1">
531→                <NavItem label={t.nav.home} icon={HomeIcon} view="home" />
532→                <NavItem label={t.nav.newAudit} icon={ScanLine} view="analyze" />
533→                <NavItem label={t.nav.dashboard} icon={LayoutDashboard} view="dashboard" />
534→                <NavItem label={t.nav.monitoringAEO} icon={Wrench} view="projects" active={['projects', 'results'].includes(currentView)} />
535→                <NavItem label={t.nav.generativeTools} icon={Sparkles} view="generative-tools" active={['generative-tools', 'smc-studio', 'source-of-truth', 'schema-org', 'robots-txt', 'content-writer', 'reputation', 'bot-tracking'].includes(currentView)} />
536→                <NavItem label={t.nav.indexedDirectory} icon={Globe} view="directory" active={['directory', 'directory-entity'].includes(currentView)} />
537→                <NavItem label={t.nav.gtoGas} icon={Fuel} view="recharge" />
538→                <NavItem label={t.nav.affiliation} icon={Share2} view="affiliation" />
539→                <NavItem label="Base Clients" icon={Users} view="clients" />
